import React, { useState } from 'react';
import { createChannel } from '../../services/api';

const ImportM3U = () => {
  const [m3uText, setM3uText] = useState('');
  const [m3uUrl, setM3uUrl] = useState('');
  const [parsed, setParsed] = useState([]);
  const [loading, setLoading] = useState(false);
  const [importing, setImporting] = useState(false);
  const [message, setMessage] = useState('');
  const [progress, setProgress] = useState(0);

  // Parsear contenido M3U
  const parseM3U = (content) => {
    const lines = content.split('\n').map(l => l.trim()).filter(Boolean);
    const channels = [];
    let current = {};

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];

      if (line.startsWith('#EXTINF')) {
        current = {};
        // Extraer nombre - solo lo que va despues de la ultima coma
        const nameMatch = line.match(/,([^,]+)$/);
        if (nameMatch) current.name = nameMatch[1].trim();

        // Extraer logo
        const logoMatch = line.match(/tvg-logo="([^"]+)"/);
        if (logoMatch) current.logo = logoMatch[1];

        // Extraer grupo/categoría
        const groupMatch = line.match(/group-title="([^"]+)"/);
        if (groupMatch) current.category = groupMatch[1];

        // Extraer país
        const countryMatch = line.match(/tvg-country="([^"]+)"/);
        if (countryMatch) current.country = countryMatch[1];

      } else if (!line.startsWith('#') && current.name) {
        // Guardar URL original, no el proxy
        current.stream_url = line.trim();
        current.country = current.country || 'Internacional';
        current.category = current.category || 'Entretenimiento';

        // Validar que sea una URL real
        if (!current.stream_url.startsWith('http')) {
          current = {};
          continue;
        }

        // Detectar tipo
        const catLower = current.category.toLowerCase();
        if (movieCategories.some(m => catLower.includes(m))) {
          current.type = 'movie';
        } else if (radioCategories.some(r => catLower.includes(r))) {
          current.type = 'radio';
        } else {
          current.type = 'tv';
        }

        channels.push({ ...current, selected: true });
        current = {};
      }
    }

    return channels;
  };

  const handleParseText = () => {
    if (!m3uText.trim()) return;
    const channels = parseM3U(m3uText);
    setParsed(channels);
    setMessage(`✅ ${channels.length} canales encontrados`);
  };

  const handleLoadUrl = async () => {
    if (!m3uUrl.trim()) return;
    setLoading(true);
    setMessage('');
    try {
      // Usar el backend como proxy para evitar CORS y seguir redirects
      const proxyUrl = `http://localhost:5000/api/channels/fetch-m3u?url=${encodeURIComponent(m3uUrl)}`;
      const response = await fetch(proxyUrl);
      if (!response.ok) throw new Error('No se pudo cargar la lista');
      const text = await response.text();
      const channels = parseM3U(text);
      if (channels.length === 0) throw new Error('No se encontraron canales en la lista');
      setParsed(channels);
      setMessage(`✅ ${channels.length} canales encontrados`);
    } catch (error) {
      setMessage('❌ Error: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      const channels = parseM3U(ev.target.result);
      setParsed(channels);
      setMessage(`✅ ${channels.length} canales encontrados`);
    };
    reader.readAsText(file);
  };

  const toggleSelect = (index) => {
    setParsed(prev => prev.map((c, i) => i === index ? { ...c, selected: !c.selected } : c));
  };

  const selectAll = () => setParsed(prev => prev.map(c => ({ ...c, selected: true })));
  const deselectAll = () => setParsed(prev => prev.map(c => ({ ...c, selected: false })));

  const handleImport = async () => {
    const selected = parsed.filter(c => c.selected);
    if (selected.length === 0) {
      setMessage('❌ Selecciona al menos un canal');
      return;
    }

    setImporting(true);
    setProgress(0);
    let success = 0;
    let errors = 0;

    // Generar ID único para esta lista
    const listId = `list_${Date.now()}`;
    const listName = m3uUrl || `Lista importada ${new Date().toLocaleDateString()}`;

    for (let i = 0; i < selected.length; i++) {
      try {
        await createChannel({ 
          ...selected[i],
          list_id: listId,
          list_name: listName
        });
        success++;
      } catch (e) {
        errors++;
      }
      setProgress(Math.round(((i + 1) / selected.length) * 100));
    }

    setImporting(false);
    setMessage(`✅ Importados: ${success} canales. ${errors > 0 ? `❌ Errores: ${errors}` : ''}`);
    setParsed([]);
  };

  return (
    <div className="max-w-4xl mx-auto p-6 text-white">
      <h1 className="text-3xl font-bold mb-6">📋 Importar Lista M3U</h1>

      {/* Opciones de carga */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
        {/* Pegar texto */}
        <div className="bg-gray-800 rounded-lg p-4">
          <h3 className="font-semibold mb-3">📝 Pegar contenido</h3>
          <textarea
            value={m3uText}
            onChange={(e) => setM3uText(e.target.value)}
            placeholder="#EXTM3U&#10;#EXTINF:-1,Canal Ejemplo&#10;http://stream.url/live.m3u8"
            className="w-full h-32 p-2 bg-gray-700 rounded text-sm resize-none focus:outline-none focus:border-red-500 border border-gray-600"
          />
          <button
            onClick={handleParseText}
            className="w-full mt-2 bg-red-600 hover:bg-red-700 py-2 rounded text-sm font-medium"
          >
            Analizar
          </button>
        </div>

        {/* URL */}
        <div className="bg-gray-800 rounded-lg p-4">
          <h3 className="font-semibold mb-3">🔗 Cargar desde URL</h3>
          <input
            type="text"
            value={m3uUrl}
            onChange={(e) => setM3uUrl(e.target.value)}
            placeholder="https://ejemplo.com/lista.m3u"
            className="w-full p-2 bg-gray-700 rounded text-sm focus:outline-none focus:border-red-500 border border-gray-600"
          />
          <button
            onClick={handleLoadUrl}
            disabled={loading}
            className="w-full mt-2 bg-red-600 hover:bg-red-700 disabled:bg-gray-600 py-2 rounded text-sm font-medium"
          >
            {loading ? 'Cargando...' : 'Cargar URL'}
          </button>
        </div>

        {/* Archivo */}
        <div className="bg-gray-800 rounded-lg p-4">
          <h3 className="font-semibold mb-3">📁 Subir archivo</h3>
          <label className="block w-full cursor-pointer">
            <div className="w-full h-32 border-2 border-dashed border-gray-600 rounded flex items-center justify-center hover:border-red-500 transition-colors">
              <div className="text-center">
                <div className="text-3xl mb-1">📂</div>
                <div className="text-sm text-gray-400">Seleccionar .m3u o .m3u8</div>
              </div>
            </div>
            <input
              type="file"
              accept=".m3u,.m3u8,.txt"
              onChange={handleFileUpload}
              className="hidden"
            />
          </label>
        </div>
      </div>

      {/* Mensaje */}
      {message && (
        <div className={`p-3 rounded mb-4 ${message.includes('❌') ? 'bg-red-900' : 'bg-green-900'}`}>
          {message}
        </div>
      )}

      {/* Progreso */}
      {importing && (
        <div className="mb-4">
          <div className="flex justify-between text-sm mb-1">
            <span>Importando...</span>
            <span>{progress}%</span>
          </div>
          <div className="w-full bg-gray-700 rounded-full h-2">
            <div
              className="bg-red-600 h-2 rounded-full transition-all"
              style={{ width: `${progress}%` }}
            />
          </div>
        </div>
      )}

      {/* Lista de canales parseados */}
      {parsed.length > 0 && (
        <div className="bg-gray-800 rounded-lg overflow-hidden">
          <div className="p-4 bg-gray-700 flex justify-between items-center">
            <div className="flex gap-4 text-sm">
              <span className="font-semibold">{parsed.filter(c => c.selected).length} / {parsed.length} seleccionados</span>
              <span className="text-blue-400">📺 TV: {parsed.filter(c => c.type === 'tv').length}</span>
              <span className="text-yellow-400">🎬 Películas: {parsed.filter(c => c.type === 'movie').length}</span>
              <span className="text-green-400">📻 Radio: {parsed.filter(c => c.type === 'radio').length}</span>
            </div>
            <div className="flex gap-2">
              <button onClick={selectAll} className="bg-green-600 hover:bg-green-700 px-3 py-1 rounded text-sm">Todos</button>
              <button onClick={deselectAll} className="bg-gray-600 hover:bg-gray-500 px-3 py-1 rounded text-sm">Ninguno</button>
              <button
                onClick={handleImport}
                disabled={importing}
                className="bg-red-600 hover:bg-red-700 disabled:bg-gray-600 px-4 py-1 rounded text-sm font-bold"
              >
                Importar Seleccionados
              </button>
            </div>
          </div>

          <div className="max-h-96 overflow-y-auto">
            {parsed.map((channel, index) => (
              <div
                key={index}
                onClick={() => toggleSelect(index)}
                className={`flex items-center gap-3 p-3 border-t border-gray-700 cursor-pointer hover:bg-gray-750 transition-colors ${channel.selected ? 'bg-gray-750' : 'opacity-50'}`}
              >
                <input
                  type="checkbox"
                  checked={channel.selected}
                  onChange={() => toggleSelect(index)}
                  className="accent-red-600"
                  onClick={e => e.stopPropagation()}
                />
                {channel.logo ? (
                  <img src={channel.logo} alt="" className="w-8 h-8 object-contain bg-white rounded p-0.5" onError={(e) => e.target.style.display = 'none'} />
                ) : (
                  <div className="w-8 h-8 bg-gray-600 rounded flex items-center justify-center text-xs">📺</div>
                )}
                <div className="flex-1 min-w-0">
                  <div className="font-medium truncate">{channel.name}</div>
                  <div className="text-xs text-gray-400 truncate">{channel.stream_url}</div>
                </div>
                <span className="text-xs bg-gray-600 px-2 py-1 rounded whitespace-nowrap">{channel.category}</span>
                <span className={`text-xs px-2 py-1 rounded whitespace-nowrap ${
                  channel.type === 'movie' ? 'bg-yellow-700' :
                  channel.type === 'radio' ? 'bg-green-700' : 'bg-blue-700'
                }`}>
                  {channel.type === 'movie' ? '🎬' : channel.type === 'radio' ? '📻' : '📺'}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default ImportM3U;
